const slug = $('Post-production').item.json.book_slug;
const chunksContent = $('Read Chunks Display').item.json.content;
const storyboardContent = $('Read Storyboard').item.json.content;
const notesContent = $('Read Notes').item.json.content;
const referenceContent = $('Read Metadata Reference').item.json.content || '(reference not available)';
let systemPrompt = $('Read Metadata Prompt').item.json.content;

if (!chunksContent) {
  throw new Error('chunks-display.md not found for book: ' + slug + '. Run script step first.');
}
if (!storyboardContent) {
  throw new Error('storyboard.md not found for book: ' + slug + '. Run storyboard step first.');
}
if (!notesContent) {
  throw new Error('notes.md not found for book: ' + slug + '. Run research step first.');
}
if (!systemPrompt) {
  throw new Error('Metadata prompt not found at n8n/prompts/metadata.md');
}

// Replace placeholders
systemPrompt = systemPrompt.replace(/\{\{book_slug\}\}/g, slug);
systemPrompt = systemPrompt.replace(/\{\{chunks_display\}\}/g, chunksContent);
systemPrompt = systemPrompt.replace(/\{\{storyboard\}\}/g, storyboardContent);
systemPrompt = systemPrompt.replace(/\{\{notes\}\}/g, notesContent);
systemPrompt = systemPrompt.replace(/\{\{metadata_reference\}\}/g, referenceContent);

const userMessage = 'Generate YouTube and Facebook metadata for the book video based on the provided chunks-display, storyboard, and notes. Follow the reference format exactly. Output the complete metadata document.';

return [{ json: { systemPrompt, userMessage, slug } }];

const slug = $('Build Metadata Prompt').item.json.slug;
const responseText = $json.content[0].text;

// Extract content between delimiters if present
let output;
const startMarker = '---OUTPUT START---';
const endMarker = '---OUTPUT END---';
const startIdx = responseText.indexOf(startMarker);
const endIdx = responseText.indexOf(endMarker);

if (startIdx !== -1 && endIdx !== -1) {
  output = responseText.substring(startIdx + startMarker.length, endIdx).trim();
} else {
  output = responseText.trim();
}

return [{ json: { slug, metadataContent: output } }];

const slug = $('Extract Metadata').item.json.slug;
const content = $('Extract Metadata').item.json.metadataContent;

// Count title options
const titleMatches = content.match(/^\d+\./gm);
const titleCount = titleMatches ? titleMatches.length : 0;

// Count shorts
const shortMatches = content.match(/^\|\s*\d+/gm);
const shortCount = shortMatches ? shortMatches.length : 0;

// Check sections present
const hasYouTube = /## YouTube/i.test(content);
const hasFacebook = /## Facebook/i.test(content);
const hasTags = /### Tags/i.test(content);
const hasShorts = /### Shorts/i.test(content);

const wordCount = content.split(/\s+/).filter(w => w.length > 0).length;

const lines = [
  'Metadata generated for: ' + slug,
  '',
  'Stats:',
  '  File: books/' + slug + '/metadata.md',
  '  Characters: ' + content.length,
  '  Words: ' + wordCount,
  '  Title options: ' + titleCount,
  '  Shorts candidates: ' + shortCount,
  '',
  'Sections:',
  '  YouTube: ' + (hasYouTube ? 'yes' : 'MISSING'),
  '  Facebook: ' + (hasFacebook ? 'yes' : 'MISSING'),
  '  Tags: ' + (hasTags ? 'yes' : 'MISSING'),
  '  Shorts: ' + (hasShorts ? 'yes' : 'MISSING'),
  '',
  'Next step: Review metadata and upload to YouTube/Facebook.'
];

return [{ json: { summary: lines.join('\n') } }];
